import { create } from 'zustand';
import { persist, subscribeWithSelector } from 'zustand/middleware';

const useCourseStore = create(
  persist(
    (set, get) => ({
      // State
      courses: [],
      favorites: [],
      enrolledCourses: [],
      user: {
        name: 'Instructor',
        email: 'instructor@example.com',
        avatar: null,
        preferences: {
          theme: 'light',
          notifications: true,
          language: 'en'
        }
      },
      notifications: [
        { id: 1, message: 'New course "Advanced React" is now available!', time: '2 min ago', unread: true, type: 'info' },
        { id: 2, message: 'Your course "Web Development" has 5 new enrollments', time: '1 hour ago', unread: true, type: 'success' },
        { id: 3, message: 'System maintenance scheduled for tonight', time: '3 hours ago', unread: false, type: 'warning' }
      ],
      analytics: {
        totalViews: 0,
        totalRevenue: 0,
        conversionRate: 0,
        popularCourses: []
      },
      loading: false,
      error: null,

      // Actions
      setCourses: (courses) => set({ courses }),

      addCourse: (course) => set((state) => ({
        courses: [...state.courses, { ...course, id: Date.now(), createdAt: new Date().toISOString() }]
      })),

      updateCourse: (courseId, updates) => set((state) => ({
        courses: state.courses.map(course => 
          course.id === courseId ? { ...course, ...updates, updatedAt: new Date().toISOString() } : course
        )
      })),

      deleteCourse: (courseId) => set((state) => ({
        courses: state.courses.filter(course => course.id !== courseId)
      })),

      toggleFavorite: (courseId) => set((state) => {
        const isFavorite = state.favorites.includes(courseId);
        return {
          favorites: isFavorite 
            ? state.favorites.filter(id => id !== courseId)
            : [...state.favorites, courseId]
        };
      }),

      enrollInCourse: (courseId) => set((state) => {
        if (!state.enrolledCourses.includes(courseId)) {
          return {
            enrolledCourses: [...state.enrolledCourses, courseId]
          };
        }
        return state;
      }),

      updateUser: (updates) => set((state) => ({
        user: { ...state.user, ...updates }
      })),

      addNotification: (notification) => set((state) => ({
        notifications: [
          { ...notification, id: Date.now(), unread: true, time: 'now' },
          ...state.notifications
        ]
      })),

      markNotificationRead: (notificationId) => set((state) => ({
        notifications: state.notifications.map(notif => 
          notif.id === notificationId ? { ...notif, unread: false } : notif
        )
      })),

      clearAllNotifications: () => set({ notifications: [] }),

      setLoading: (loading) => set({ loading }),

      setError: (error) => set({ error }),

      updateAnalytics: (analytics) => set((state) => ({
        analytics: { ...state.analytics, ...analytics }
      })),

      // Computed values
      getStats: () => {
        const state = get();
        return {
          totalCourses: state.courses.length,
          totalStudents: state.courses.reduce((sum, course) => sum + (course.enrolled || 0), 0),
          totalRevenue: state.courses.reduce((sum, course) => sum + ((course.price || 0) * (course.enrolled || 0)), 0),
          avgRating: state.courses.length > 0 
            ? (state.courses.reduce((sum, course) => sum + parseFloat(course.rating || 0), 0) / state.courses.length).toFixed(1) 
            : '0.0',
          unreadNotifications: state.notifications.filter(n => n.unread).length
        };
      },

      getFavoriteCourses: () => {
        const state = get();
        return state.courses.filter(course => state.favorites.includes(course.id));
      },

      getEnrolledCourses: () => {
        const state = get();
        return state.courses.filter(course => state.enrolledCourses.includes(course.id));
      }
    }),
    {
      name: 'course-store',
      partialize: (state) => ({
        courses: state.courses,
        favorites: state.favorites,
        enrolledCourses: state.enrolledCourses,
        user: state.user,
        notifications: state.notifications
      })
    }
  )
);

export default useCourseStore;
